// RegisterTools registers all API operations as MCP tools.
func RegisterTools(s *server.MCPServer) {
	s.AddTool(
		mcplib.NewTool("devices_list",
			mcplib.WithDescription("List every Dreo device on your account. Returns array of Device."),
			mcplib.WithReadOnlyHintAnnotation(true),
			mcplib.WithDestructiveHintAnnotation(false),
			mcplib.WithOpenWorldHintAnnotation(true),
		),
		makeAPIHandler("GET", "/api/v2/user-device/device/list", false, []mcpParamBinding{}, []string{}),
	)
	s.AddTool(
		mcplib.NewTool("devices_state",
			mcplib.WithDescription("Read the current state snapshot for one device. Required: deviceSn. Returns the DeviceState."),
			mcplib.WithString("deviceSn", mcplib.Required(), mcplib.Description("Device serial number (from `devices list`)")),
			mcplib.WithReadOnlyHintAnnotation(true),
			mcplib.WithDestructiveHintAnnotation(false),
			mcplib.WithOpenWorldHintAnnotation(true),
		),
		makeAPIHandler("GET", "/api/user-device/device/state", false, []mcpParamBinding{{PublicName: "deviceSn", WireName: "deviceSn", Location: "query"}}, []string{}),
	)
	s.AddTool(
		mcplib.NewTool("firmware_check",
			mcplib.WithDescription("Check whether a firmware update is available for a device. Required: deviceSn. Returns the new FirmwareCheckResult."),
			mcplib.WithString("deviceSn", mcplib.Required(), mcplib.Description("Device serial number")),
			mcplib.WithDestructiveHintAnnotation(false),
			mcplib.WithOpenWorldHintAnnotation(true),
		),
		makeAPIHandler("POST", "/api/upgrade/device/check", false, []mcpParamBinding{{PublicName: "deviceSn", WireName: "deviceSn", Location: "body"}}, []string{}),
	)
	s.AddTool(
		mcplib.NewTool("settings_get",
			mcplib.WithDescription("Get persistent settings for a device. Required: deviceSn. Returns the DeviceSettings."),
			mcplib.WithString("deviceSn", mcplib.Required(), mcplib.Description("Device serial number")),
			mcplib.WithReadOnlyHintAnnotation(true),
			mcplib.WithDestructiveHintAnnotation(false),
			mcplib.WithOpenWorldHintAnnotation(true),
		),
		makeAPIHandler("GET", "/api/user-device/setting", false, []mcpParamBinding{{PublicName: "deviceSn", WireName: "deviceSn", Location: "query"}}, []string{}),
	)
	s.AddTool(
		mcplib.NewTool("settings_update",
			mcplib.WithDescription("Update persistent settings for a device. Required: deviceSn. Optional: settings. Returns the updated DeviceSettings."),
			mcplib.WithString("deviceSn", mcplib.Required(), mcplib.Description("Device serial number")),
			mcplib.WithString("settings", mcplib.Description("Settings JSON blob to update (model-specific shape)")),
			mcplib.WithOpenWorldHintAnnotation(true),
		),
		makeAPIHandler("PUT", "/api/user-device/setting", false, []mcpParamBinding{{PublicName: "deviceSn", WireName: "deviceSn", Location: "body"}, {PublicName: "settings", WireName: "settings", Location: "body"}}, []string{}),
	)

	// Context tool — front-loaded domain knowledge for agents.
	// Call this first to understand the API taxonomy, query patterns, and capabilities.
	s.AddTool(
		mcplib.NewTool("context",
			mcplib.WithDescription("Get API domain context: resource taxonomy, auth requirements, query tips, and unique capabilities. Call this first."),
			mcplib.WithReadOnlyHintAnnotation(true),
			mcplib.WithDestructiveHintAnnotation(false),
		),
		handleContext,
	)

	// Runtime Cobra-tree mirror — exposes every user-facing command that is
	// not already covered by a typed endpoint or framework MCP tool.
	cobratree.RegisterAll(s, cli.RootCmd(), cobratree.SiblingCLIPath)
}

